import React, { useState } from "react";
import "./styles/App.css";
import BillingScreen from "./components/BillingScreen";
import FoodMenu from "./components/FoodMenu";
import RecentBills from "./components/RecentBills";
import AdminDashboard from "./components/AdminDashboard";

function LoginPanel({ onLogin }) {
  const [credential, setCredential] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const [track, setTrack] = useState("");
  const [loading, setLoading] = useState(false);

  const submit = () => {
    if (credential.trim()) {
      setLoading(true);
      setTimeout(() => {
        const mode =
          credential.toLowerCase().includes("admin") ||
          credential.toLowerCase().includes("shi")
            ? "admin"
            : "clerk";
        onLogin(mode, date, track);
        setLoading(false);
      }, 1000);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      submit();
    }
  };

  if (loading) {
    return (
      <div className="login-container">
        <div className="login-panel">
          <div className="system-title">
            Udupi Anand Bhavan — Billing System
          </div>

          <div className="verification-section">
            <div className="spinner"></div>
            <div className="verification-text">
              <div>Verifying Admin Access...</div>
              <div className="sub-text">Press the key combination now</div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="login-container">
      <div className="login-panel">
        <div className="system-title">Udupi Anand Bhavan — Billing System</div>

        <div className="staff-access-section">
          <div className="section-header">
            <span className="lock-icon">🔒</span>
            <span>Staff Access</span>
          </div>

          <div className="form-field">
            <label>Credential</label>
            <input
              type="text"
              value={credential}
              onChange={(e) => setCredential(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="shi"
            />
          </div>

          <div className="form-field">
            <label>Date</label>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              onKeyPress={handleKeyPress}
            />
          </div>

          <div className="form-field">
            <label>Track</label>
            <input
              type="text"
              value={track}
              onChange={(e) => setTrack(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder="--"
            />
          </div>

          <button
            onClick={submit}
            className="enter-button"
            disabled={!credential.trim()}
          >
            Enter
          </button>

          <div className="help-text">
            Hint: Use 'CLK' for clerk, 'SHI' for admin, or 'SHI' + Shift+Enter
            for root admin.
          </div>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [mode, setMode] = useState("none");
  const [billingDate, setBillingDate] = useState(
    new Date().toISOString().split("T")[0]
  );
  const [track, setTrack] = useState("");
  const [activeTab, setActiveTab] = useState("billing");

  const handleLogin = (newMode, date, trackValue) => {
    console.log("Login successful:", newMode, date, trackValue);
    setMode(newMode || "clerk");
    setBillingDate(date || billingDate);
    setTrack(trackValue || "");
    setActiveTab("billing");
  };

  const handleLogout = () => {
    setMode("none");
    setActiveTab("login");
    setTrack("");
  };

  if (mode === "none") {
    return <LoginPanel onLogin={handleLogin} />;
  }

  const isAdmin = mode && mode.includes("admin");

  if (isAdmin) {
    return (
      <AdminDashboard
        billingDate={billingDate}
        onLogout={handleLogout}
        userMode={mode}
        track={track}
      />
    );
  }

  return (
    <div className="main-app">
      <div className="app-header">
        <div className="system-title">Udupi Anand Bhavan — Billing System</div>
        <div className="logout-section">
          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </div>

      <div className="app-nav">
        <div className="nav-tabs">
          <button
            className={`nav-tab ${activeTab === "billing" ? "active" : ""}`}
            onClick={() => setActiveTab("billing")}
          >
            📋 Billing
          </button>
          <button
            className={`nav-tab ${activeTab === "menu" ? "active" : ""}`}
            onClick={() => setActiveTab("menu")}
          >
            🍽️ Food Menu
          </button>
          <button
            className={`nav-tab ${activeTab === "bills" ? "active" : ""}`}
            onClick={() => setActiveTab("bills")}
          >
            📄 Recent Bills
          </button>
          {isAdmin && (
            <button
              className={`nav-tab ${activeTab === "admin" ? "active" : ""}`}
              onClick={() => setActiveTab("admin")}
            >
              ⚙️ Admin
            </button>
          )}
        </div>
      </div>

      <div className="app-content">
        {activeTab === "billing" && (
          <BillingScreen
            billingDate={billingDate}
            userMode={mode}
            track={track}
          />
        )}
        {activeTab === "menu" && <FoodMenu />}
        {activeTab === "bills" && <RecentBills billingDate={billingDate} />}
        {activeTab === "admin" && isAdmin && (
          <AdminDashboard
            billingDate={billingDate}
            onLogout={handleLogout}
            userMode={mode}
            track={track}
          />
        )}
      </div>
    </div>
  );
}
